package com.hospital.management.validation;import com.hospital.management.model.*;import org.junit.jupiter.api.*;import static org.junit.jupiter.api.Assertions.*;class RoomAndBedValidatorTest{@Test void validatesRoom(){RoomForm f=new RoomForm();f.setRoomNumber("101-A");f.setRoomType("GENERAL");f.setFloorNumber("1");f.setDailyRate("1500.00");f.setStatus("ACTIVE");assertFalse(new RoomValidator().validate(f).hasErrors());f.setRoomType("BAD");f.setFloorNumber("999");f.setDailyRate("-1");f.setStatus("BAD");assertTrue(new RoomValidator().validate(f).hasErrors());}@Test void validatesBed(){BedForm f=new BedForm();f.setRoomId(1L);f.setBedNumber("B1");f.setStatus("AVAILABLE");assertFalse(new BedValidator().validate(f).hasErrors());f.setRoomId(null);f.setBedNumber("");f.setStatus("BAD");assertTrue(new BedValidator().validate(f).hasErrors());}}
